  ('dietitian-moex-04743', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品良好衛生規範準則，食品業者使用清潔劑、消毒劑及有毒化學物質使用規定之敘述，下 列何者錯誤？', '["應符合相關主管機關之規定方得使用", "應予明確標示，存放於固定場所", "應指定專人負責保管", "應實施領用登記，上鎖管制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
